# Load required libraries\nlibrary(ggplot2)\nlibrary(sp)\nlibrary(rgdal)\nlibrary(sf)\n\n# Load sampling points CSV\nsampling_points <- read.csv("path/to/your/sampling_points.csv")\n\n# Generate a 400x444 meter grid\nlon_range <- c(min(sampling_points$longitude), max(sampling_points$longitude))\nlat_range <- c(min(sampling_points$latitude), max(sampling_points$latitude))\ngrid <- expand.grid(\n  x = seq(lon_range[1], lon_range[2], length.out = 400),\n  y = seq(lat_range[1], lat_range[2], length.out = 444)\n)\n\n# Convert to spatial points\ncoordinates(grid) <- ~x+y\nproj4string(grid) <- CRS("+proj=utm +zone=14 +datum=WGS84 +units=m +no_defs")\n\n# Create a static map\nstatic_map <- ggplot() +\n  geom_point(data = sampling_points, aes(x = longitude, y = latitude), color = 'blue') +\n  coord_equal() +\n  xlab("Longitude") +\n  ylab("Latitude") +\n  ggtitle("Static Map of Sampling Points in Zimapán")\nggsave(filename = "C:/BIOREMEDIACION_2026_0228/Mapas/Malla_Zimapan/static_map.png", plot = static_map, width = 10, height = 8)\n\n# Create a dynamic map (using leaflet)\nlibrary(leaflet)\ndynamic_map <- leaflet(data = sampling_points) %>%\n  addTiles() %>%\n  addMarkers(~longitude, ~latitude, popup = ~as.character(sampling_point_name))\nsaveWidget(dynamic_map, "C:/BIOREMEDIACION_2026_0228/Mapas/Malla_Zimapan/dynamic_map.html", selfcontained = TRUE)